mapper.select:
select id, tenant_id, workflow_definition_id, workflow_code, version,
       workflow_name, workflow_type, enabled,
       nodes_json::text as nodes_json,
       edges_json::text as edges_json,
       saved_by, saved_at, summary
from batch.workflow_definition_version
where tenant_id = #{tenantId}
  and workflow_definition_id = #{workflowDefinitionId}
  and version = #{version}
limit 1
